() => {
  // Set a standard viewport and wait
  window.scrollTo(0, 0);
  const h = document.documentElement.scrollHeight;
  const w = document.documentElement.scrollWidth;
  return { scrollHeight: h, scrollWidth: w, vh: window.innerHeight, vw: window.innerWidth, theme: document.documentElement.className, bg: getComputedStyle(document.body).backgroundColor, fg: getComputedStyle(document.body).color };
}

() => {
  // Walk sections and describe their background/color plus id/dataset/label
  const sections = Array.from(document.querySelectorAll('section, header, footer, main > *'));
  return sections.slice(0, 40).map((el, i) => {
    const r = el.getBoundingClientRect();
    const cs = getComputedStyle(el);
    const inner = el.innerText?.slice(0, 70).replace(/\s+/g,' ').trim() || '';
    return {
      i,
      tag: el.tagName.toLowerCase(),
      cls: el.className?.toString().slice(0, 120),
      topAbs: Math.round(r.top + window.scrollY),
      h: Math.round(r.height),
      bg: cs.backgroundColor,
      color: cs.color,
      preview: inner,
    };
  });
}

