input.script:
() => {
  // Find all text elements visible in the hero (first 800px)
  const all = Array.from(document.querySelectorAll('*'));
  const results = [];
  for (const el of all) {
    const r = el.getBoundingClientRect();
    const top = r.top + window.scrollY;
    if (top > 800 || r.height === 0 || r.width === 0) continue;
    const text = el.childNodes.length && Array.from(el.childNodes).some(n => n.nodeType === 3 && n.textContent.trim())
      ? (el.innerText||'').trim() : '';
    if (!text) continue;
    const cs = getComputedStyle(el);
    results.push({
      tag: el.tagName.toLowerCase(),
      text: text.slice(0, 100).replace(/\s+/g,' '),
      color: cs.color,
      bg: cs.backgroundColor,
      opacity: cs.opacity,
      fontSize: cs.fontSize,
      top: Math.round(top),
      cls: (el.className?.toString()||'').slice(0,100),
    });
  }
  return results.slice(0, 25);
}

() => {
  const h1 = document.querySelector('h1');
  // Walk up to find which rule sets color
  const rules = [];
  const sheets = Array.from(document.styleSheets);
  for (const s of sheets) {
    try {
      const r = Array.from(s.cssRules || []);
      for (const rule of r) {
        if (!rule.style) continue;
        const color = rule.style.color;
        if (!color) continue;
        if (rule.selectorText && /ht-blue|ht_blue/i.test(rule.selectorText)) {
          rules.push({ sel: rule.selectorText, color });
        }
      }
    } catch(e) {}
  }
  // Also test direct properties
  const cs = getComputedStyle(h1);
  return { color: cs.color, rules, classList: h1.className };
}

