input.script:
() => {
  // Inspect all sections in dark mode for bg/color and flag dark-on-dark or light-on-light
  const sections = Array.from(document.querySelectorAll('section, header, footer, main > div'));
  const report = [];
  for (const el of sections) {
    const r = el.getBoundingClientRect();
    const top = r.top + window.scrollY;
    const cs = getComputedStyle(el);
    // Get effective background by walking up
    let bg = cs.backgroundColor;
    let cur = el;
    while (cur && (bg === 'rgba(0, 0, 0, 0)' || bg === 'transparent') && cur.parentElement) {
      cur = cur.parentElement;
      bg = getComputedStyle(cur).backgroundColor;
    }
    report.push({
      tag: el.tagName.toLowerCase(),
      top: Math.round(top),
      h: Math.round(r.height),
      effectiveBg: bg,
      color: cs.color,
      cls: (el.className||'').toString().slice(0, 100),
      preview: (el.textContent || '').slice(0, 50).replace(/\s+/g, ' ').trim(),
    });
  }
  return report.slice(0, 30);
}

