() => {
  const targets = ['More, not less', 'The easy answer', 'The surface reading', 'Your questions answered', 'Every Monday'];
  const out = [];
  const els = Array.from(document.querySelectorAll('h1,h2,h3,h4,p,span'));
  for (const t of targets) {
    const el = els.find(e => new RegExp(t.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')).test(e.textContent.slice(0, 200)));
    if (!el) continue;
    const cs = getComputedStyle(el);
    let bg = cs.backgroundColor, cur = el;
    while (cur && (bg==='rgba(0, 0, 0, 0)'||bg==='transparent') && cur.parentElement) { cur = cur.parentElement; bg = getComputedStyle(cur).backgroundColor; }
    out.push({
      target: t,
      text: el.textContent.slice(0, 60),
      tag: el.tagName,
      color: cs.color,
      effBg: bg,
      cls: el.className.toString().slice(0, 140),
    });
  }
  return out;
}

